
INSERT INTO vcr_items (category_id, vcr_item, supporting_evidence, guidance_notes, delivering_party_role_id, approving_party_role_ids, display_order, is_active) VALUES
-- DESIGN INTEGRITY (4 items)
('dc57de6c-1b34-4604-8ec4-58d8b9e50b84', 'Does the design and construction of the new asset—or modification to the existing asset—comply with the standards and requirements defined in the approved Basis for Design (BfD), including DEM-1?', 'DEM 1 Compliance Report', E'• Confirm the design and construction comply with the approved Basis for Design (BfD) and all relevant engineering standards, including DEM-1.\n• Ensure all deviations or waivers from design standards are formally approved, documented, and captured as Qualifications.', '88c54747-e81f-47ff-9574-7f982f8520cc', ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','23d61604-150c-4edd-8338-30a1da3ab6fb','2827cd71-6ae8-4ece-821b-f4ce9ae6cebc','c0ca8a85-a102-4248-b3bd-0d57e67ec844','414a5aa3-b962-4884-a7db-c8e12326514a','f0284734-bc04-45c7-aeed-9d55e232b450','14defdba-4739-4e4e-a94e-c5c560531dc2','6bbd12f4-cad2-4ccb-8e73-8710cdca2216','a62ea10e-9b1e-4917-81f4-2d0a91a0756d']::uuid[], 1, true),

('dc57de6c-1b34-4604-8ec4-58d8b9e50b84', 'Does the design and construction of the new asset, or the modification to the existing asset, meet the Process Safety Basic Requirements defined in DEM-2?', 'DEM 2 Compliance Report', E'• Verify that the design and construction comply with all applicable Process Safety Basic Requirements (PSBRs) as defined in DEM-2.\n• Review and document any deviations or derogations from DEM-2 requirements, ensuring they are formally approved, risk-assessed, and captured as Qualifications where applicable.', '88c54747-e81f-47ff-9574-7f982f8520cc', ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','23d61604-150c-4edd-8338-30a1da3ab6fb','2827cd71-6ae8-4ece-821b-f4ce9ae6cebc','c0ca8a85-a102-4248-b3bd-0d57e67ec844','414a5aa3-b962-4884-a7db-c8e12326514a','f0284734-bc04-45c7-aeed-9d55e232b450','14defdba-4739-4e4e-a94e-c5c560531dc2','6bbd12f4-cad2-4ccb-8e73-8710cdca2216','a62ea10e-9b1e-4917-81f4-2d0a91a0756d']::uuid[], 2, true),

('dc57de6c-1b34-4604-8ec4-58d8b9e50b84', 'Have all actions generated from the HEMP process (e.g., OMARs, HAZOP, HAZID, IPF Studies, QRAs, etc.) been fully closed out?', 'HEMP Close out Report, OMAR Close out Report, Design HSSE Case', E'• All outstanding actions arising from HEMP studies have been captured and raised as qualifications, with clear ownership and closure plans.\n• All process safety risks are fully identified, assessed, and recorded in the Hazard and Effects Register.\n• A detailed Major Accident Hazard (MAH) analysis has been performed, including escalation pathways, barrier performance, and safeguarding measures.', '88c54747-e81f-47ff-9574-7f982f8520cc', ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','23d61604-150c-4edd-8338-30a1da3ab6fb','2827cd71-6ae8-4ece-821b-f4ce9ae6cebc','c0ca8a85-a102-4248-b3bd-0d57e67ec844','414a5aa3-b962-4884-a7db-c8e12326514a','f0284734-bc04-45c7-aeed-9d55e232b450','14defdba-4739-4e4e-a94e-c5c560531dc2','6bbd12f4-cad2-4ccb-8e73-8710cdca2216','a62ea10e-9b1e-4917-81f4-2d0a91a0756d','11d4cc74-146e-48d5-9a98-922dbf8c08f0']::uuid[], 3, true),

('dc57de6c-1b34-4604-8ec4-58d8b9e50b84', 'Has Operational ALARP been demonstrated, including SIMOPS and MOPO requirements, and documented in the Operational HSSE Case?', 'Operations HSSE Case, ALARP Demonstration Report', E'• The Operations HSSE Case has been fully completed, formally approved, and cascaded to all relevant personnel.\n• There is clear demonstration that all HSSE risks are tolerable and have been reduced to ALARP.\n• All Safety-Critical Elements (SCEs) have been identified, documented, and incorporated into the Operations HSSE Case.', '88c54747-e81f-47ff-9574-7f982f8520cc', ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','23d61604-150c-4edd-8338-30a1da3ab6fb','2827cd71-6ae8-4ece-821b-f4ce9ae6cebc','c0ca8a85-a102-4248-b3bd-0d57e67ec844','414a5aa3-b962-4884-a7db-c8e12326514a','f0284734-bc04-45c7-aeed-9d55e232b450','14defdba-4739-4e4e-a94e-c5c560531dc2','6bbd12f4-cad2-4ccb-8e73-8710cdca2216','a62ea10e-9b1e-4917-81f4-2d0a91a0756d']::uuid[], 4, true),

-- TECHNICAL INTEGRITY (15 items)
('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Have all Construction and Commissioning scopes been completed, verified, and accepted, with no outstanding works that could impact system readiness, safety, or handover to Operations?', 'Completions Dossiers, Completions Reports', E'• All Construction and Commissioning activities must be completed and verified, including Mechanical Completion, functional testing, and closure of A and B punch items.\n• Documentation must be fully updated and accepted.\n• Any remaining works must be reviewed and confirmed as non-impacting to safety, operability, or system readiness.', '88c54747-e81f-47ff-9574-7f982f8520cc', ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','23d61604-150c-4edd-8338-30a1da3ab6fb','2827cd71-6ae8-4ece-821b-f4ce9ae6cebc','c0ca8a85-a102-4248-b3bd-0d57e67ec844','414a5aa3-b962-4884-a7db-c8e12326514a','f0284734-bc04-45c7-aeed-9d55e232b450','6bbd12f4-cad2-4ccb-8e73-8710cdca2216','1d6b2c15-5283-4800-904e-9849672a20a2','11d4cc74-146e-48d5-9a98-922dbf8c08f0']::uuid[], 5, true),

('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Have all MOC actions been completed and verified on site, and have any remaining actions been checked to ensure they pose no safety or operational risk?', 'Project MOC Report', E'• All MOC actions have been implemented, verified on site, and fully reflected in updated documentation.\n• Technical Authority approval has been obtained for all completed changes.\n• Any remaining MOC actions have been reviewed and risk-assessed, confirming no safety, integrity, regulatory, or operational impact.', '88c54747-e81f-47ff-9574-7f982f8520cc', ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','23d61604-150c-4edd-8338-30a1da3ab6fb','2827cd71-6ae8-4ece-821b-f4ce9ae6cebc','c0ca8a85-a102-4248-b3bd-0d57e67ec844','414a5aa3-b962-4884-a7db-c8e12326514a','f0284734-bc04-45c7-aeed-9d55e232b450','6bbd12f4-cad2-4ccb-8e73-8710cdca2216','1d6b2c15-5283-4800-904e-9849672a20a2','11d4cc74-146e-48d5-9a98-922dbf8c08f0']::uuid[], 6, true),

('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Have all outstanding temporary project MoCs been reviewed and updated in the Asset MoC system to ensure full traceability?', 'Temp MOC Report', E'• All temporary project MoCs must be reviewed and validated, ensuring the technical intent, risks, and justifications are accurately captured before transfer.\n• Each temporary MoC must be fully migrated into the Asset MoC system, maintaining end-to-end traceability.\n• Any residual actions or risks must be assessed and confirmed as non-impacting to safety or operations.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','23d61604-150c-4edd-8338-30a1da3ab6fb','2827cd71-6ae8-4ece-821b-f4ce9ae6cebc','c0ca8a85-a102-4248-b3bd-0d57e67ec844','414a5aa3-b962-4884-a7db-c8e12326514a','f0284734-bc04-45c7-aeed-9d55e232b450','6bbd12f4-cad2-4ccb-8e73-8710cdca2216','1d6b2c15-5283-4800-904e-9849672a20a2','11d4cc74-146e-48d5-9a98-922dbf8c08f0','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 7, true),

('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Have all Site Technical Queries (STQs) been reviewed, approved by the appropriate Technical Authorities, and fully implemented?', 'STQ Register, NCR Register', E'• All STQs must be formally reviewed and approved by the appropriate Technical Authorities before any work is executed or accepted.\n• Approved STQs must be implemented exactly as instructed and verified on site.\n• All associated documentation must be updated.', '88c54747-e81f-47ff-9574-7f982f8520cc', ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','23d61604-150c-4edd-8338-30a1da3ab6fb','2827cd71-6ae8-4ece-821b-f4ce9ae6cebc','c0ca8a85-a102-4248-b3bd-0d57e67ec844','414a5aa3-b962-4884-a7db-c8e12326514a','f0284734-bc04-45c7-aeed-9d55e232b450','6bbd12f4-cad2-4ccb-8e73-8710cdca2216','1d6b2c15-5283-4800-904e-9849672a20a2']::uuid[], 8, true),

('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Have all Safety-Critical Elements (SCEs) been identified and tested against the applicable SCE Performance Standards?', 'TIV Report', E'• Evidence confirms that the Technical Integrity of all SCEs has been assured through systematic application of QA processes and execution of the approved TIV Plan.\n• All SCE-related punch list items have been resolved and closed.\n• The final TIV Report has been completed, reviewed, approved, and formally issued.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','23d61604-150c-4edd-8338-30a1da3ab6fb','2827cd71-6ae8-4ece-821b-f4ce9ae6cebc','c0ca8a85-a102-4248-b3bd-0d57e67ec844','414a5aa3-b962-4884-a7db-c8e12326514a','f0284734-bc04-45c7-aeed-9d55e232b450','6bbd12f4-cad2-4ccb-8e73-8710cdca2216']::uuid[], 9, true),

('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Does the equipment or facility performance test meet the agreed performance test criteria?', 'Performance Test Report', E'• Performance tests must be executed according to the approved test procedure.\n• Test results must be validated against the agreed performance criteria.\n• Final acceptance requires formal sign-off by relevant Technical Authorities and Asset representatives.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','23d61604-150c-4edd-8338-30a1da3ab6fb','2827cd71-6ae8-4ece-821b-f4ce9ae6cebc','c0ca8a85-a102-4248-b3bd-0d57e67ec844','414a5aa3-b962-4884-a7db-c8e12326514a','f0284734-bc04-45c7-aeed-9d55e232b450','11d4cc74-146e-48d5-9a98-922dbf8c08f0','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 10, true),

('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Have all Safeguarding and Emergency Shutdown systems been successfully tested and verified against the approved Cause & Effects (C&E) drawings?', 'Cause & Effect Sheet', E'• All safeguarding and ESD functions must be tested and verified against the approved C&E matrix.\n• Test results must be evidenced and signed off by Commissioning, Operations, and the appropriate Technical Authorities.\n• C&E diagrams, SIF registers, and related documentation must be updated.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['23d61604-150c-4edd-8338-30a1da3ab6fb']::uuid[], 11, true),

('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Are all Fire and Gas (F&G) systems fully tested and confirmed to be in service?', 'FGS Cause & Effect Sheet', E'• Verify that all F&G detectors, panels, alarms, and trip functions have been function-tested and confirmed to operate per the approved C&E matrices.\n• Confirm that any inhibited, bypassed, or overridden F&G points have been removed from bypass and returned to service.\n• Ensure field verification has been completed.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['23d61604-150c-4edd-8338-30a1da3ab6fb']::uuid[], 12, true),

('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Has a tightness review been completed, confirming all required flange torquing?', 'Flange Management Report', E'• Verify that all flanges associated with isolations, reinstatement, and system preparation have been correctly torqued and documented.\n• Confirm that the tightness review includes any required re-checks following changes in temperature, pressure, or operating conditions.\n• Ensure field verification has been completed.', '82b98733-1690-4d04-b2bb-e9c24ec18325', ARRAY['c0ca8a85-a102-4248-b3bd-0d57e67ec844']::uuid[], 13, true),

('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Are all Relief Valves in service, correctly lined-up, tagged, and within valid certification?', 'PSV Certificates', E'• Verify that all Relief Valves (PSVs/PRVs) are in service and correctly lined-up.\n• Confirm each Relief Valve is tagged and traceable.\n• Ensure all Relief Valves have current certification and are within their inspection and test validity period.', '82b98733-1690-4d04-b2bb-e9c24ec18325', ARRAY['c0ca8a85-a102-4248-b3bd-0d57e67ec844']::uuid[], 14, true),

('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Have all applicable equipment been leak-tested and confirmed oxygen-free?', 'Leak Test Report, ITRs', E'• Verify all equipment requiring leak-testing has been tested.\n• Confirm oxygen-free status using an Authorized Gas Tester (AGT).\n• Ensure all test results have been documented, communicated, and re-checked after breaks or operational changes.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['c0ca8a85-a102-4248-b3bd-0d57e67ec844']::uuid[], 15, true),

('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Is the pipeline or piping system clean, dry, and confirmed to meet the required dew point?', 'Cleanliness & Dryness Report', E'• Confirm that the piping/pipeline has been fully drained, flushed, purged, and vented.\n• Ensure drying is complete and the measured dew point meets the required specification.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['c0ca8a85-a102-4248-b3bd-0d57e67ec844','11d4cc74-146e-48d5-9a98-922dbf8c08f0','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6','e2d8885b-f7ba-40af-88c6-f58c561858ce']::uuid[], 16, true),

('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Has the baseline Pipeline Intelligent Pigging (IP) data been completed, validated, and formally provided to the Asset?', 'Baseline IP result', E'• Confirm that baseline IP inspection results have been delivered to the Asset.\n• Verify the results have been reviewed by the relevant Discipline Authorities.\n• Ensure the Asset team has access to the baseline data in an approved repository.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['c0ca8a85-a102-4248-b3bd-0d57e67ec844','14defdba-4739-4e4e-a94e-c5c560531dc2','e2d8885b-f7ba-40af-88c6-f58c561858ce']::uuid[], 17, true),

('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Is the Cathodic Protection (CP) System in service and functioning correctly?', 'DCVG and CIPS Reports', E'• Verify that the CP system is energized, operational, and providing adequate protection.\n• Confirm that all CP readings, rectifier outputs, potentials, and alarms are within acceptable limits.\n• Ensure inspection and maintenance records are current.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['2827cd71-6ae8-4ece-821b-f4ce9ae6cebc','c0ca8a85-a102-4248-b3bd-0d57e67ec844','e2d8885b-f7ba-40af-88c6-f58c561858ce']::uuid[], 18, true),

('aa833d21-cc27-4cea-aa2a-be0a31dec44b', 'Have all Ex (Hazardous Area) Equipment been inspected and confirmed to be within valid certification?', 'Ex Register', E'• Verify that all Ex-rated electrical and instrumentation equipment in hazardous areas has undergone the required inspections.\n• Confirm that each item of Ex equipment is within its valid inspection/certification period.\n• Ensure Ex equipment condition is verified in the field.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['2827cd71-6ae8-4ece-821b-f4ce9ae6cebc']::uuid[], 19, true),

-- OPERATING INTEGRITY (17 items)
('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Have all findings from audits, reviews, and health checks (e.g., PSUA, PSUR, ORR) been fully closed out?', 'Action Close-Out Report', E'• Verify that all findings and actions from PSSR, PSUA, PSUR, ORR, and other audits or reviews are completed.\n• Ensure any open items have been risk-assessed and confirmed not to impact safety or operability.\n• Confirm that closure evidence is documented and stored in the approved repository.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['1d6b2c15-5283-4800-904e-9849672a20a2','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 20, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Has the required Operations & Maintenance Organization been identified and resourced?', 'Organization Chart (with names)', E'• Competency Management Framework & Plan for Operations and Maintenance staff is in place.\n• Technical & HSE critical positions competence criteria has been defined and agreed.\n• HSE Critical Positions have been identified and staff nominated.\n• Personnel in HSSE Critical Roles are fit for work.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['1d6b2c15-5283-4800-904e-9849672a20a2','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 21, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Have all identified and agreed training requirements been completed?', 'Training Records', E'• Verify that all required competency-based, mandatory, and role-specific training has been completed.\n• Confirm that project-specific and facility-specific training has been delivered and acknowledged.\n• Ensure any outstanding or expired training has been risk-assessed.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 22, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Have Red-Line Mark-Ups (RLMU/RLMP) for all Tier 1 and Tier 2 Critical Drawings and Documents been prepared, approved, and transferred to the Asset?', 'Tier 1 & 2 Documents', E'• All Tier 1 & Tier 2 Critical Documents and Drawings must be red-lined to as-built status, formally reviewed, and approved.\n• Controlled copies at site and office must be current and accurate.\n• All Operations and Maintenance documentation must be complete and reflect the final installed condition.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['1d6b2c15-5283-4800-904e-9849672a20a2','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 23, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Are the Initial Start-Up and Normal Operating Procedures approved for use and formally handed over to the Asset?', 'Initial Start-Up Procedures, Normal Operating Procedures', E'• Verify that all Initial Start-Up, Normal Operating, and related system operating procedures have been fully developed, reviewed, and approved.\n• Confirm that the procedures reflect the final as-built design and commissioning scope.\n• Ensure the approved procedures have been formally handed over to the Asset.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','23d61604-150c-4edd-8338-30a1da3ab6fb','2827cd71-6ae8-4ece-821b-f4ce9ae6cebc','c0ca8a85-a102-4248-b3bd-0d57e67ec844','414a5aa3-b962-4884-a7db-c8e12326514a','f0284734-bc04-45c7-aeed-9d55e232b450','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 24, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Have all overrides been reviewed and documented in the Override Register?', 'Override Register', E'• Verify that all active, temporary, and historical overrides are recorded in the Override Register.\n• Confirm that each override has been formally reviewed by Operations and the relevant Technical Authorities.\n• Ensure that overrides have been communicated through shift handovers and PTW/SIMOPS processes.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['23d61604-150c-4edd-8338-30a1da3ab6fb','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 25, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Has the Variable Table been updated and implemented, and have all inhibited alarms been reactivated?', 'Variable Table, Alarm Management Report', E'• Verify that all Variable Table limits and parameters have been updated and implemented in the DCS.\n• Confirm that all inhibited, disabled, shelved, or bypassed alarms have been reviewed and returned to service.\n• Ensure alignment between the updated Variable Table, Master Alarm Database, and actual DCS configuration.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['23d61604-150c-4edd-8338-30a1da3ab6fb','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 26, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Have all process and electrical isolations been reviewed, confirmed safe, and verified as correctly in place?', 'Isolation Register', E'• Verify that all process and electrical isolations have been reviewed, field-checked, and confirmed to be correctly applied.\n• Ensure all required isolations necessary to safely introduce hydrocarbons are in place and correctly documented.\n• Confirm that isolation status poses no safety or operational risk.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','2827cd71-6ae8-4ece-821b-f4ce9ae6cebc','c0ca8a85-a102-4248-b3bd-0d57e67ec844','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 27, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Has the blind list been fully reviewed, and are all temporary blinds removed with all specification blinds correctly installed?', 'Spade Register', E'• Verify that all blinds are correctly recorded, reviewed, and aligned with the isolation plan.\n• Confirm that all temporary blinds have been removed, and only the correct specification blinds are installed.\n• Ensure field verification has been completed.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','c0ca8a85-a102-4248-b3bd-0d57e67ec844','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 28, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Have all Temporary Equipment items been removed from site, or certified and recorded in the Temporary Equipment Register?', NULL, E'• Verify that all Temporary Equipment has been removed from the facility unless explicitly required for start-up or ongoing operations.\n• Confirm that any Temporary Equipment still in service is fully certified, fit-for-purpose, and entered into the Temporary Equipment Register.\n• Ensure all anomalies or expired certificates are resolved.', '88c54747-e81f-47ff-9574-7f982f8520cc', ARRAY['1d6b2c15-5283-4800-904e-9849672a20a2','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 29, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Have all combustible materials, temporary piping, scaffolding materials, and shutdown materials been fully removed from site?', NULL, E'• Verify that all combustible or flammable materials, temporary piping, hoses, scaffolding components, and surplus shutdown materials have been removed.\n• Confirm the site has been cleared and restored to normal operating condition.\n• Perform a physical field walk-down to ensure no remaining materials pose a hazard.', '88c54747-e81f-47ff-9574-7f982f8520cc', ARRAY['1d6b2c15-5283-4800-904e-9849672a20a2','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 30, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Has the Locked Open / Locked Closed (LOLC) register been fully updated and verified in the field?', 'LOLC Register', E'• Confirm the LO/LC register is fully updated with all valves designated as Locked Open or Locked Closed.\n• Verify valve positions in the field by physically checking each LO/LC valve against the register.\n• Ensure all anomalies are resolved or escalated.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['1d6b2c15-5283-4800-904e-9849672a20a2','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 31, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Have all vent and drain checks been completed and are all sewers uncovered and free of debris?', NULL, E'• Verify that all drain and vent points are intact and correctly fitted with the required plugs, caps, or connections.\n• Confirm that all open drains, channels, and sewers are uncovered, unobstructed, and free from debris.\n• Ensure a physical field walk-down has been performed.', '82b98733-1690-4d04-b2bb-e9c24ec18325', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 32, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Is the start-up organization fully defined, adequately resourced, and supported by the required specialist vendors?', 'SU Organization Chart', E'• Verify that the full start-up organisation structure is defined and resourced.\n• Confirm that all required specialist vendors are mobilised, available, and contracted.\n• Ensure that all start-up personnel and vendors have completed required training and site inductions.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['1d6b2c15-5283-4800-904e-9849672a20a2','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 33, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Have all affected units and departments been notified of the planned start-up activities?', 'SU Notification email', E'• Confirm that all impacted teams have received formal notification of start-up timing, scope, and SIMOPS implications.\n• Verify that cross-functional coordination has taken place.\n• Ensure communication has been documented and acknowledged.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 34, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Has a Start-Up on Paper (SUOP) exercise been completed, and have all outstanding actions been closed out?', 'SUOP Action Register, MoM', E'• Verify that the SUOP walkthrough has been completed with participation from all relevant teams.\n• Confirm that all issues, gaps, and risks identified during the SUOP have been logged and fully closed out.\n• Ensure SUOP outcomes have been incorporated into start-up procedures and PTW/MOPO/SIMOPS plans.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 35, true),

('52e040a1-4edc-4847-9fea-f8a07605fb71', 'Has a detailed assessment of the incident or equipment failure been completed, with all actions closed or fully mitigated?', 'RCA Report', E'• Verify that the incident or equipment failure has been fully assessed, with root cause, contributing factors, and required mitigations identified.\n• Confirm all corrective actions are closed, risk-assessed, or formally mitigated.\n• Ensure the findings and mitigations have been cascaded to relevant teams.', NULL, ARRAY['a71de5b4-8dc4-4ae5-8907-3ba35bd87342','23d61604-150c-4edd-8338-30a1da3ab6fb','2827cd71-6ae8-4ece-821b-f4ce9ae6cebc','c0ca8a85-a102-4248-b3bd-0d57e67ec844','414a5aa3-b962-4884-a7db-c8e12326514a','f0284734-bc04-45c7-aeed-9d55e232b450','14defdba-4739-4e4e-a94e-c5c560531dc2','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6']::uuid[], 36, true),

-- MANAGEMENT SYSTEMS (13 items)
('d2d6fcbd-dff4-46f3-8a1e-50e241edbfdb', 'Has the Asset Register, Preventive Maintenance (PM) routines, and Bills of Materials (BOMs) been fully built, validated, and loaded into the CMMS?', 'ARB, PM and BOM Report', E'• Ensure the Asset Register, PM routines, and BOMs are fully developed, quality-checked, and aligned with engineering deliverables.\n• Verify that all data has been validated and successfully loaded into the CMMS.\n• Confirm that any gaps or outstanding items have been risk-assessed and raised as Qualifications.', 'cf134725-32a2-4b55-bfd4-dd4e45682d9d', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','60ba58d0-b295-4a24-88e9-139b15d3d101']::uuid[], 37, true),

('d2d6fcbd-dff4-46f3-8a1e-50e241edbfdb', 'Have all applicable Preventive Maintenance (PM) routines been fully activated in the CMMS?', 'PM Scheduling Report', E'• Verify that all applicable PM routines have been activated in the CMMS, correctly linked to equipment tags.\n• Confirm that activation includes scheduling, resource requirements, and materials/BOM associations.\n• Ensure any unactivated or deferred PM routines are reviewed, risk-assessed, and raised as Qualifications.', 'cf134725-32a2-4b55-bfd4-dd4e45682d9d', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','60ba58d0-b295-4a24-88e9-139b15d3d101']::uuid[], 38, true),

('d2d6fcbd-dff4-46f3-8a1e-50e241edbfdb', 'Is the Integrity Management System (IMS/PLSS) updated to reflect the project scope and activated in accordance with the approved Corrosion Management Framework (CMF)?', 'IMS/ PLSS Report', E'• Ensure the IMS/PLSS is fully updated with all new or modified assets, including corrosion loops, degradation mechanisms, and inspection requirements.\n• Verify that all integrity and corrosion management workflows are activated.\n• Confirm that any gaps or outstanding updates have been reviewed and risk-assessed.', 'cf134725-32a2-4b55-bfd4-dd4e45682d9d', ARRAY['c0ca8a85-a102-4248-b3bd-0d57e67ec844','14defdba-4739-4e4e-a94e-c5c560531dc2','11d4cc74-146e-48d5-9a98-922dbf8c08f0','60ba58d0-b295-4a24-88e9-139b15d3d101']::uuid[], 39, true),

('d2d6fcbd-dff4-46f3-8a1e-50e241edbfdb', 'Have the 2-Year Operating Spares been procured and formally handed over to the Asset?', 'STK Report, PR-PO Report', E'• Verify that all 2-Year Operating Spares identified in the approved spares list have been fully procured.\n• Confirm that all procured spares have been inspected, catalogued, and properly entered into the CMMS/warehouse management system.\n• Ensure that the spares have been formally handed over to the Asset with complete documentation.', 'cf134725-32a2-4b55-bfd4-dd4e45682d9d', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','60ba58d0-b295-4a24-88e9-139b15d3d101']::uuid[], 40, true),

('d2d6fcbd-dff4-46f3-8a1e-50e241edbfdb', 'Have all required Capital Spares been procured and formally handed over to the Asset?', 'Capital Spares Report, PR-PO Report', E'• Verify that all Capital Spares required for startup and early operations have been fully procured.\n• Confirm that the spares have been formally handed over to the Asset with documentation.\n• Ensure the Asset team has visibility and access to the spare parts.', 'cf134725-32a2-4b55-bfd4-dd4e45682d9d', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','60ba58d0-b295-4a24-88e9-139b15d3d101']::uuid[], 41, true),

('d2d6fcbd-dff4-46f3-8a1e-50e241edbfdb', 'Is the Facility Status Report (FSR) or similar, updated to reflect the integrity status of the new or modified facility?', 'FSR Dashboard screen shot', E'• Ensure the FSR tool is fully updated to reflect the latest integrity status of the new or modified facility.\n• Verify that all integrity-related data is accurate, complete, and aligned with supporting documentation.\n• Confirm that any outstanding issues impacting integrity are clearly captured in the FSR.', 'cf134725-32a2-4b55-bfd4-dd4e45682d9d', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','60ba58d0-b295-4a24-88e9-139b15d3d101']::uuid[], 42, true),

('d2d6fcbd-dff4-46f3-8a1e-50e241edbfdb', 'Are all required Operations and Maintenance (O&M) contracts in place and valid?', NULL, E'• Verify that all essential O&M contracts are fully executed, valid, and active.\n• Ensure contract scopes, deliverables, rates, and response times align with operational needs.\n• Confirm that all contractor mobilization, onboarding, competence requirements, and HSSE obligations are complete.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','60ba58d0-b295-4a24-88e9-139b15d3d101']::uuid[], 43, true),

('d2d6fcbd-dff4-46f3-8a1e-50e241edbfdb', 'Are all Operational Registers fully updated, accurate, and verified?', 'Operational Registers', E'• Verify that all operational registers are fully updated to reflect current field conditions.\n• Confirm that each register has undergone the required physical verification and review.\n• Ensure that all related MoC, work requests, audits, and documentation updates have been completed.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6','60ba58d0-b295-4a24-88e9-139b15d3d101']::uuid[], 44, true),

('d2d6fcbd-dff4-46f3-8a1e-50e241edbfdb', 'Are the Operator Logsheets updated to reflect the current scope and available for use?', 'Operator Logsheets', E'• Verify that the Operator Logsheets have been updated to include all parameters, limits, and tasks.\n• Confirm that logsheets are available at the point of use and reflect the latest monitoring frequencies.\n• Ensure any changes arising from commissioning or start-up readiness have been incorporated.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6','60ba58d0-b295-4a24-88e9-139b15d3d101']::uuid[], 45, true),

('d2d6fcbd-dff4-46f3-8a1e-50e241edbfdb', 'Have all required PI tags and associated ProcessBook/PI Vision displays been updated, configured, and activated?', 'PI Report & screen shot', E'• Verify that all required PI tags are created, mapped, and validated.\n• Confirm that ProcessBook or equivalent visualization tools have been updated.\n• Ensure full end-to-end functionality has been validated.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6','60ba58d0-b295-4a24-88e9-139b15d3d101']::uuid[], 46, true),

('d2d6fcbd-dff4-46f3-8a1e-50e241edbfdb', 'Have all relevant software, system backups, licenses, and tools been successfully transferred from the Project team to the Asset team?', 'P2A Transmittal Letter', E'• Verify that all software, system backups, digital configurations, and licenses have been fully transferred to the Asset.\n• Confirm that all physical and digital tools have been handed over.\n• Ensure documentation is complete and stored in approved Asset repositories.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['23d61604-150c-4edd-8338-30a1da3ab6fb','11d4cc74-146e-48d5-9a98-922dbf8c08f0','60ba58d0-b295-4a24-88e9-139b15d3d101']::uuid[], 47, true),

('d2d6fcbd-dff4-46f3-8a1e-50e241edbfdb', 'Has the Integrated Activity Plan (IAP) been updated to include the new or upgraded facility and aligned with the Strategic Asset Management Plan (SAMP)?', 'IAP Report, SAMP', E'• Verify that the IAP has been updated to incorporate all activities related to the new or upgraded facility.\n• Ensure alignment between the IAP and the Strategic Asset Management Plan (SAMP).\n• Confirm that the updated IAP has been reviewed and endorsed by all relevant teams.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','3791edef-e263-4515-97b8-512b99b9f026']::uuid[], 48, true),

('d2d6fcbd-dff4-46f3-8a1e-50e241edbfdb', 'Is the Hydrocarbon Allocation/Accounting application updated to reflect the Asset current allocation structure?', NULL, E'• Ensure the application is fully updated with the Asset current allocation structure.\n• Verify that allocation logic, formulas, meter factors, and data mappings have been configured, validated, and tested.\n• Confirm all interfaces are functioning correctly.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','3791edef-e263-4515-97b8-512b99b9f026']::uuid[], 49, true),

-- HEALTH & SAFETY (9 items)
('0347791a-eaae-42ea-be42-1fb90022df38', 'Is the Asset Permit to Work (PTW) system fully operational, and has PTW custodianship been formally transferred from the Project to the Asset?', 'Signed off PtW Custodianship Transfer Form', E'• Verify that the PTW system is functioning under Asset control.\n• Confirm that PTW roles are assigned within the Asset, with a valid signatory matrix and appointment letters in place.\n• Ensure custodianship of PTW has been fully transferred from the Project to the Asset.', '88c54747-e81f-47ff-9574-7f982f8520cc', ARRAY['1d6b2c15-5283-4800-904e-9849672a20a2','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6','465c909e-3927-4afe-8239-9f136a9c5bb0','a62ea10e-9b1e-4917-81f4-2d0a91a0756d']::uuid[], 50, true),

('0347791a-eaae-42ea-be42-1fb90022df38', 'Have all construction and commissioning permits been fully suspended or closed?', NULL, E'• Verify that all construction and commissioning permits have been suspended or closed in the PTW system.\n• Confirm that associated isolations have been closed or transferred to Extended Period Isolations (EPIs).\n• Ensure the Project team has handed over all PTW documentation and records to the Asset.', 'd88df696-db5f-4952-b685-1b907b472dcb', ARRAY['1d6b2c15-5283-4800-904e-9849672a20a2','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6','465c909e-3927-4afe-8239-9f136a9c5bb0','a62ea10e-9b1e-4917-81f4-2d0a91a0756d']::uuid[], 51, true),

('0347791a-eaae-42ea-be42-1fb90022df38', 'Is the Emergency Response Plan (including Pre-Incident Plans, PIPs) reviewed, updated, and cascaded to all relevant teams?', 'Pre-Incidence Plans (PIP)', E'• Verify that all Emergency Response documents have been reviewed and updated to reflect current facility configuration.\n• Confirm that PIPs have been communicated and cascaded to all relevant personnel.\n• Ensure the updated Emergency Response Plan and PIPs are accessible, visible, and integrated into drills.', '1ec91356-b1d8-4ca5-bd83-23da1af40614', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6','1ec91356-b1d8-4ca5-bd83-23da1af40614']::uuid[], 52, true),

('0347791a-eaae-42ea-be42-1fb90022df38', 'Have Emergency Response (ER) Teams been notified of the start-up, and are they fully resourced and equipped to respond?', 'Email confirmation from ERT Lead', E'• Verify that the ER Team has been formally notified of the planned start-up.\n• Confirm that the ER Team is fully staffed, competent, and available.\n• Ensure all ER equipment is in service and ready.', '5cb2b79d-b60c-40a1-ab79-50410da2c8c7', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','1ec91356-b1d8-4ca5-bd83-23da1af40614']::uuid[], 53, true),

('0347791a-eaae-42ea-be42-1fb90022df38', 'Have all staff received the site-specific HSE induction and demonstrated competence in emergency alarms, muster point requirements, and escalation procedures?', 'Training Records, Attendance Sheet', E'• Verify that every staff member and contractor has completed the mandatory site-specific HSE induction.\n• Confirm staff understand how to respond to emergency alarms.\n• Ensure all personnel are familiar with escalation procedures.', '88c54747-e81f-47ff-9574-7f982f8520cc', ARRAY['11d4cc74-146e-48d5-9a98-922dbf8c08f0','465c909e-3927-4afe-8239-9f136a9c5bb0','a62ea10e-9b1e-4917-81f4-2d0a91a0756d']::uuid[], 54, true),

('0347791a-eaae-42ea-be42-1fb90022df38', 'Have Site Access Controls been fully implemented, and have all prerequisites for safe site access been fully met?', NULL, E'• Verify that full Site Access Control measures are in place.\n• Confirm safe-access prerequisites are provided and used, including escape respirators, Personal Gas Monitors, and required PPE.\n• Ensure site-control rules are enforced.', '88c54747-e81f-47ff-9574-7f982f8520cc', ARRAY['1d6b2c15-5283-4800-904e-9849672a20a2','11d4cc74-146e-48d5-9a98-922dbf8c08f0','80b335be-6937-4b34-95ef-94830c64c35d','c58a58d4-9dfd-46b4-8404-454c04e3f790','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6','465c909e-3927-4afe-8239-9f136a9c5bb0','a62ea10e-9b1e-4917-81f4-2d0a91a0756d']::uuid[], 55, true),

('0347791a-eaae-42ea-be42-1fb90022df38', 'Are all Escape Routes clearly marked and free of obstruction?', NULL, E'• Verify that all designated escape routes and emergency pathways are clearly marked and visible.\n• Confirm escape routes are fully free of obstructions.\n• Ensure personnel are familiar with escape routing as part of the site-specific HSE induction.', '82b98733-1690-4d04-b2bb-e9c24ec18325', ARRAY['465c909e-3927-4afe-8239-9f136a9c5bb0','a62ea10e-9b1e-4917-81f4-2d0a91a0756d']::uuid[], 56, true),

('0347791a-eaae-42ea-be42-1fb90022df38', 'Has a Fire & Safety Audit been completed with all actions closed out, and are all safety-critical equipment correctly located and in service?', 'Fire Audit Report', E'• Verify that a Fire & Safety audit has been conducted and all outstanding actions are closed.\n• Confirm all safety equipment is in service and correctly located.\n• Ensure emergency equipment supports ER team capability.', '465c909e-3927-4afe-8239-9f136a9c5bb0', ARRAY['465c909e-3927-4afe-8239-9f136a9c5bb0']::uuid[], 57, true),

('0347791a-eaae-42ea-be42-1fb90022df38', 'Have all required regulatory approvals been obtained, and are systems in place to ensure ongoing regulatory compliance?', 'Permits', E'• Verify that all mandatory regulatory approvals have been received, such as License-to-Operate (LTO), environmental discharge permits, flare consents, and waste-handling permits.\n• Ensure regulatory obligations have been cascaded to relevant teams.', '88c54747-e81f-47ff-9574-7f982f8520cc', ARRAY['1d6b2c15-5283-4800-904e-9849672a20a2','11d4cc74-146e-48d5-9a98-922dbf8c08f0','99d4e4cf-829f-42e7-bfa0-1f14814807c5','761eb276-fdd5-4c5d-8d72-a75e00b0fbf6','9c2503ac-1aee-4552-bc2a-9ae9b05e25c4']::uuid[], 58, true);
